const jobs = $input.all();

return [{
  json: {
    totalJobs: jobs.length,
    descriptions: jobs.map(job => ({
      title: job.json.title,
      company: job.json.companyName,
      description: job.json.descriptionText
    }))
  }
}];

const rawOutput = $json.output || '';

// Remove markdown fences
let cleaned = rawOutput
  .replace(/```json\s*/gi, '')
  .replace(/```/g, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  // Attempt basic JSON repairs
  try {
    cleaned = cleaned
      .replace(/,\s*}/g, '}')   // remove trailing commas in objects
      .replace(/,\s*]/g, ']')   // remove trailing commas in arrays
      .replace(/[\u0000-\u001F]+/g, ' '); // remove control chars

    parsed = JSON.parse(cleaned);
  } catch (secondError) {
    return [{
      json: {
        skills: [],
        top_skills: [],
        technical_skills_count: 0,
        soft_skills_count: 0,
        highlighted_skills: [],
        parse_error: secondError.message
      }
    }];
  }
}

return [
  {
    json: {
      skills: parsed.skills || [],
      top_skills: parsed.top_skills || [],
      technical_skills_count: parsed.technical_skills_count || 0,
      soft_skills_count: parsed.soft_skills_count || 0,
      highlighted_skills: parsed.highlighted_skills || []
    }
  }
];

// Get market skills from previous node
const marketSkills = $('AI Agent output parser').first().json.skills || [];

// Get user skills from Airtable
const skillRecords = $(' Fetch Skill Profile — Airtable').all();

const mySkills = skillRecords.map(item =>
  String(item.json['Skill Name'] || '')
    .toLowerCase()
    .trim()
);

// Find missing skills
const gaps = marketSkills
  .filter(skill =>
    !mySkills.includes(skill.name.toLowerCase())
  )
  .sort((a, b) => {
    const order = {
      high: 0,
      medium: 1,
      low: 2
    };

    return (order[a.frequency] ?? 999) -
           (order[b.frequency] ?? 999);
  });

const topSkill = gaps[0] || null;

// Find category for the top skill if it exists in Airtable
const topSkillCategory = skillRecords.map(item =>
  String(item.json['Category'] || '')
    .toLowerCase()
    .trim()
);;

if (topSkill) {
  const matchingSkill = skillRecords.find(item =>
    String(item.json['Skill Name'] || '')
      .toLowerCase()
      .trim() === topSkill.name.toLowerCase()
  );

//   topSkillCategory = matchingSkill
//     ? matchingSkill.json.Category || null
//     : topSkill.category || null;
}

// Get original jobs from Apify
const jobs = $('Get dataset items').all();

// Find jobs mentioning the top missing skill
const top5Jobs = topSkill
  ? jobs
      .filter(job =>
        (job.json.descriptionText || '')
          .toLowerCase()
          .includes(topSkill.name.toLowerCase())
      )
      .slice(0, 5)
      .map(job => ({
        title: job.json.title,
        company: job.json.companyName,
        location: job.json.location?.fullAddress,
        url: job.json.jobUrl
      }))
  : [];

return [{
  json: {
    targetRole: 'AI Engineer',
    gaps,
    topSkill,
    topSkillCategory,
    top5Jobs,
    totalGaps: gaps.length,
    timestamp: new Date().toISOString()
  }
}];

